const tagBadges=document.querySelectorAll(".tag-badge");tagBadges.forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const t=this.dataset.tag;filterPosts(t),tagBadges.forEach(e=>e.classList.remove("active")),this.classList.add("active")})});function filterPosts(e){const t=document.querySelectorAll(".portfolio-item");t.forEach(t=>{if(e==="all"){t.style.display="block";return}t.classList.contains("tag-"+e)?t.style.display="block":t.style.display="none"})}